import { useEffect, useMemo, useRef, useState } from "react";

// Constante para el desplazamiento superior al hacer scroll
const SCROLL_OFFSET = 100;

export default function Index() {
  const sections = useMemo(
    () => [
      {
        id: "objective",
        title: "OBJECTIVE",
        displayTitle: "Objective",
        body: (
          <p>
            Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian
            companies with more than 40 years of trajectory. We digitize archives, certify milestones,
            and curate living narratives that honor legacy while inspiring the next generation of leaders.
          </p>
        ),
      },
      {
        id: "mission",
        title: "MISSION",
        displayTitle: "Mission",
        body: (
          <p>
            To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful
            storytelling, and timeless design—making each company's journey accessible, verifiable, and
            beautifully preserved for the future.
          </p>
        ),
      },
      {
        id: "vision",
        title: "VISION",
        displayTitle: "Vision",
        body: (
          <p>
            A prestigious national archive where the history of business excellence is treasured—
            a reference for researchers, entrepreneurs, and families that elevates the legacy of
            Bolivian industry on the world stage.
          </p>
        ),
      },
      {
        id: "origin",
        title: "ORIGIN",
        displayTitle: "Origin",
        body: (
          <p>
            Born from a commitment to cultural memory, Orbis Empresarial emerged when historians,
            archivists, and innovators united around a single idea: if we don't document our
            enterprises today, tomorrow's generations will inherit silence where there should be legacy.
          </p>
        ),
      },
      {
        id: "how",
        title: "HOW IT STARTED",
        displayTitle: "How It Started",
        body: (
          <div className="w-full">
            <div className="relative overflow-x-auto md:overflow-visible px-2 py-6">
              <div
                className="absolute left-6 right-6 md:left-8 md:right-8 top-1/2 -translate-y-1/2 h-[1px] rounded-full bg-gradient-to-r from-transparent via-navy/20 to-transparent"
              />
              <ol className="relative z-10 flex min-w-[640px] md:min-w-0 items-start gap-10 md:gap-12 lg:gap-16 px-4 md:px-8 snap-x">
                {[
                  { year: "1980s", text: "Foundational archives collected across departments." },
                  { year: "1990s", text: "First private–public preservation partnerships." },
                  { year: "2000s", text: "Digitization program and certification standards." },
                  { year: "2010s", text: "Interactive exhibits and institutional expansion." },
                  { year: "Today", text: "A living platform connecting legacy with innovation." },
                ].map((m) => (
                  <li key={m.year} className="snap-center min-w-[160px]">
                    <div className="flex flex-col items-center text-center gap-3">
                      <div className="relative">
                        <span className="block w-2 h-2 rounded-full bg-navy" />
                      </div>
                      <div className="text-sm font-light tracking-wide">
                        <span className="font-serif text-lg block mb-1 text-navy">{m.year}</span>
                        <span className="block max-w-[16rem] text-xs leading-tight text-navy/80">{m.text}</span>
                      </div>
                    </div>
                  </li>
                ))}
              </ol>
            </div>
          </div>
        ),
      },
    ],
    [],
  );

  const [active, setActive] = useState(sections[0].id);
  const sectionRefs = useRef({});

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        let bestEntry = null;
        for (const entry of entries) {
            if (!bestEntry || entry.intersectionRatio > bestEntry.intersectionRatio) {
                if (entry.intersectionRatio > 0.25) {
                    bestEntry = entry;
                }
            }
        }
        if (bestEntry) {
          setActive(bestEntry.target.id);
        }
      },
      { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: "-20% 0px -40% 0px" },
    );

    sections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, [sections]);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - SCROLL_OFFSET;
    
    window.scrollTo({
      top: offsetPosition,
      behavior: "smooth"
    });
    setActive(id);
  };

  return (
    <div className="bg-beige text-navy min-h-screen font-sans">
      <main className="mx-auto max-w-5xl px-6 py-12">
        <header className="text-left mb-16">
          <h1 className="font-serif text-5xl lg:text-6xl font-normal leading-tight tracking-tight mb-4">
            Orbis<br />Empresarial
          </h1>
          <div className="h-px w-20 mb-6 bg-navy"></div>
          <p className="text-lg font-light tracking-wide max-w-md text-navy/90">
            Preserving the living history of Bolivian companies 40+ years strong.
          </p>
        </header>

        <div className="flex flex-col lg:flex-row gap-16">
          <aside className="lg:w-8/8">
            <nav className="flex lg:flex-col gap-1">
              {sections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`text-left py-3 px-1 transition-all duration-300 border-b lg:border-b-0 lg:border-l-2 ${
                    active === s.id 
                      ? 'font-medium border-navy' 
                      : 'font-light opacity-70 border-navy/30'
                  }`}
                >
                  <span className="tracking-widest text-sm">{s.title}</span>
                </a>
              ))}
            </nav>
          </aside>

          <section className="lg:w-5/7 flex flex-col gap-20">
            {sections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (sectionRefs.current[s.id] = el)}
                // =====> MODIFICACIÓN: Se cambiaron los valores de padding a p-12 y lg:p-16 <=====
                className="scroll-mt-24 bg-white p-12 lg:p-16 rounded-xl shadow-md border border-transparent hover:border-navy hover:shadow-lg transition-all duration-300 ease-in-out overflow-hidden"
              >
                <div
                  className={`transition-opacity duration-700 ${
                    active === s.id ? "opacity-100" : "opacity-80"
                  }`}
                >
                  <div className="mb-8">
                    <h2 className="font-serif text-3xl font-normal mb-4 tracking-wide">
                      {s.displayTitle}
                    </h2>
                    <div className="h-px w-16 bg-navy"></div>
                  </div>

                  <div>
                    <div className="text-lg leading-relaxed font-light tracking-wide text-navy/95 max-w-prose">
                      {s.body}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </section>
        </div>

        <footer className="mt-24 pt-8 border-t border-navy/20 text-center">
          <p className="text-sm font-light tracking-wide text-navy/60">
            © {new Date().getFullYear()} Orbis Empresarial
          </p>
        </footer>
      </main>
    </div>
  );
}
